from dataclasses import dataclass, field
from typing import Any
import statistics

@dataclass
class PersonaCluster:
    """Aggregate research signals into a single persona."""
    participant_ids: list[str]
    literacy_scores:  list[int]   # 0-4 from diary coding
    trust_scores:     list[float] # 1-5 Likert
    harm_codes:       list[str]   # qualitative codes

    def ai_literacy_level(self) -> int:
        """Median literacy, rounded to nearest integer."""
        return round(statistics.median(self.literacy_scores))

    def trust_calibration(self) -> str:
        m = statistics.mean(self.trust_scores)
        if m >= 4.0:
            return "over"
        if m <= 2.5:
            return "under"
        return "calibrated"

    def dominant_harm_severity(self) -> str:
        severity_rank = {
            "negligible": 0, "minor": 1, "moderate": 2,
            "significant": 3, "severe": 4
        }
        ranked = sorted(
            set(self.harm_codes),
            key=lambda c: severity_rank.get(c, 0),
            reverse=True
        )
        return ranked[0] if ranked else "negligible"

    def to_persona_attrs(self) -> dict[str, Any]:
        return {
            "ai_literacy_level":  self.ai_literacy_level(),
            "trust_calibration":  self.trust_calibration(),
            "harm_severity":      self.dominant_harm_severity(),
        }

from dataclasses import dataclass

@dataclass
class AcceptanceCriterion:
    given: str
    when:  str
    then:  str
    persona_source: str  # which persona attribute generated this

    def gherkin(self) -> str:
        return (
            f"GIVEN {self.given}\n"
            f"WHEN  {self.when}\n"
            f"THEN  {self.then}\n"
            f"# Source: persona.{self.persona_source}"
        )

def acs_from_persona(persona: "AIPersona") -> list[AcceptanceCriterion]:
    criteria: list[AcceptanceCriterion] = []
    if persona.ai_literacy_level <= 1:
        criteria.append(AcceptanceCriterion(
            given="the AI returns a result",
            when="the user has not requested details",
            then="a plain-language rationale is visible without additional clicks",
            persona_source="ai_literacy_level"
        ))
    if persona.trust_calibration == "over":
        criteria.append(AcceptanceCriterion(
            given="model confidence is below the configured threshold",
            when="a result is displayed",
            then="a low-confidence indicator is shown prominently alongside the result",
            persona_source="trust_calibration"
        ))
    if persona.harm_severity in ("significant", "severe"):
        criteria.append(AcceptanceCriterion(
            given="an action with high harm potential is triggered",
            when="the AI recommends or executes the action",
            then="a mandatory human review step blocks completion until approved",
            persona_source="harm_severity"
        ))
    if persona.is_vulnerable_user:
        criteria.append(AcceptanceCriterion(
            given="content touches a flagged sensitive topic",
            when="the content is rendered",
            then="safe-messaging guidelines and appropriate referral links are displayed",
            persona_source="is_vulnerable_user"
        ))
    return criteria

from dataclasses import dataclass, field
from typing import Optional

@dataclass
class PersonaRegistry:
    """Central store for all product personas."""
    personas: dict[str, "AIPersona"] = field(default_factory=dict)

    def register(self, persona: "AIPersona") -> None:
        self.personas[persona.name] = persona

    def personas_for_literacy(self, level: int) -> list["AIPersona"]:
        return [p for p in self.personas.values() if p.ai_literacy_level == level]

    def high_harm_personas(self) -> list["AIPersona"]:
        high = {"significant", "severe"}
        return [p for p in self.personas.values()
                if p.harm_severity in high]

    def coverage_report(self) -> dict:
        """Quick coverage matrix for QA planning."""
        return {
            "total": len(self.personas),
            "by_literacy": {
                lvl: len(self.personas_for_literacy(lvl))
                for lvl in range(5)
            },
            "by_trust": {
                t: sum(1 for p in self.personas.values()
                       if p.trust_calibration == t)
                for t in ("over", "calibrated", "under")
            },
            "high_harm_count": len(self.high_harm_personas()),
            "vulnerable_count": sum(
                1 for p in self.personas.values() if p.is_vulnerable_user
            ),
        }
